const payload = $input.first().json;
const person = payload.person || payload.visitor || payload;

// Determine company_id from the page URL domain
let companyId = 1; // Default Grand Park Capital
const pageUrl = (person.page_url || payload.page_url || '').toLowerCase();
if (pageUrl.includes('brandnewnow') || pageUrl.includes('bnn')) companyId = 2;
if (pageUrl.includes('tikkun')) companyId = 4;

return [{
  json: {
    person: {
      email: person.email,
      first_name: person.first_name || person.firstName,
      last_name: person.last_name || person.lastName,
      phone: person.phone || null,
      company_name: person.company_name || person.company,
      title: person.title || person.job_title,
      linkedin_url: person.linkedin_url || person.linkedin,
      page_url: pageUrl
    },
    company_id: companyId
  }
}];
